  { emoji: '🦠', nom: 'Virus', points: 10, vitesse: 1.2, couleur: '#ff4444' },
  { emoji: '💀', nom: 'Hacker', points: 20, vitesse: 1.8, couleur: '#ff6600' },
  { emoji: '🐛', nom: 'Bug', points: 15, vitesse: 1.5, couleur: '#ffaa00' },
  { emoji: '👾', nom: 'Malware', points: 30, vitesse: 2.2, couleur: '#ff00ff' },
];

function MiniJeu() {
  const [actif, setActif] = useState(false);
  const [score, setScore] = useState(0);
  const [highscore, setHighscore] = useState(0);
  const [vies, setVies] = useState(3);
  const [ennemis, setEnnemis] = useState([]);
  const [explosions, setExplosions] = useState([]);
  const [gameOver, setGameOver] = useState(false);
  const [niveau, setNiveau] = useState(1);
  const [combo, setCombo] = useState(0);
  const [comboDisplay, setComboDisplay] = useState(null);
  const zoneRef = useRef(null);
  const intervalRef = useRef(null);
  const tickRef = useRef(null);
  const idRef = useRef(0);
  const comboRef = useRef(0);

  const stopJeu = useCallback(() => {
    clearInterval(intervalRef.current);
    clearInterval(tickRef.current);
  }, []);

  const demarrer = () => {
    setScore(0); setVies(3); setEnnemis([]); setExplosions([]);
    setGameOver(false); setNiveau(1); setCombo(0); comboRef.current = 0;
    setActif(true);
  };

  useEffect(() => {
    if (!actif || gameOver) return;
    const vitesseSpawn = Math.max(800, 1800 - niveau * 150);
    intervalRef.current = setInterval(() => {
      const type = ENNEMIS_TYPES[Math.floor(Math.random() * ENNEMIS_TYPES.length)];
      const zone = zoneRef.current;
      if (!zone) return;
      const w = zone.offsetWidth;
      setEnnemis(prev => [...prev, {
        id: idRef.current++,
        x: Math.random() * (w - 60) + 10,
        y: -50,
        ...type,
        vy: type.vitesse + niveau * 0.3,
        taille: 40 + Math.random() * 20,
      }]);
    }, vitesseSpawn);
    return () => clearInterval(intervalRef.current);
  }, [actif, gameOver, niveau]);

  useEffect(() => {
    if (!actif || gameOver) return;
    tickRef.current = setInterval(() => {
      const zone = zoneRef.current;
      if (!zone) return;
      const h = zone.offsetHeight;
      setEnnemis(prev => {
        const survivants = [];
        let touchés = 0;
        for (const e of prev) {
          if (e.y > h) { touchés++; }
          else { survivants.push({ ...e, y: e.y + e.vy }); }
        }
        if (touchés > 0) {
          setVies(v => {
            const nv = v - touchés;
            if (nv <= 0) { setGameOver(true); setActif(false); stopJeu(); return 0; }
            return nv;
          });
          comboRef.current = 0; setCombo(0);
        }
        return survivants;
      });
      setScore(s => {
        const ns = s + Math.floor(niveau * 0.5);
        setNiveau(Math.floor(ns / 200) + 1);
        return ns;
      });
    }, 30);
    return () => clearInterval(tickRef.current);
  }, [actif, gameOver, niveau, stopJeu]);

  const tuerEnnemi = (id, x, y, points) => {
    comboRef.current += 1;
    setCombo(comboRef.current);
    const bonus = comboRef.current >= 3 ? comboRef.current : 1;
    const gain = points * bonus;
    setScore(s => s + gain);
    setEnnemis(prev => prev.filter(e => e.id !== id));
    setExplosions(prev => [...prev, { id: Date.now(), x, y, gain, combo: comboRef.current }]);
    if (comboRef.current >= 3) {
      setComboDisplay({ val: comboRef.current, x, y });
      setTimeout(() => setComboDisplay(null), 800);
    }
    setTimeout(() => setExplosions(prev => prev.filter(e => e.id !== Date.now())), 600);
  };

  useEffect(() => {
    if (gameOver && score > highscore) setHighscore(score);
  }, [gameOver, score, highscore]);

  return (
    <div style={{ width: '100%', maxWidth: '700px', margin: '0 auto', fontFamily: "'Rajdhani', sans-serif" }}>
      <style>{`
        @keyframes explode { 0%{transform:scale(0.5);opacity:1;} 100%{transform:scale(2.5);opacity:0;} }
        @keyframes floatUp { 0%{transform:translateY(0);opacity:1;} 100%{transform:translateY(-60px);opacity:0;} }
        @keyframes ennemiBounce { 0%,100%{transform:rotate(-5deg) scale(1);} 50%{transform:rotate(5deg) scale(1.1);} }
        @keyframes shakeZone { 0%,100%{transform:translateX(0);} 25%{transform:translateX(-5px);} 75%{transform:translateX(5px);} }
        @keyframes comboFlash { 0%{transform:scale(0.5) rotate(-10deg);opacity:0;} 50%{transform:scale(1.3) rotate(5deg);opacity:1;} 100%{transform:scale(1) rotate(0deg);opacity:0;} }
        .ennemi-sprite { cursor: crosshair; animation: ennemiBounce 0.6s ease-in-out infinite; user-select:none; transition: transform 0.1s; }
        .ennemi-sprite:active { transform: scale(0.8) !important; }
      `}</style>

      {/* HEADER JEU */}
      <div style={{ background: 'rgba(10,15,30,0.9)', border: '1px solid rgba(255,215,0,0.2)', borderRadius: '16px 16px 0 0', padding: '16px 24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div style={{ color: '#ffd700', fontSize: '0.75rem', letterSpacing: '3px', textTransform: 'uppercase', marginBottom: '4px' }}>Score</div>
          <div style={{ color: '#fff', fontSize: '1.8rem', fontFamily: "'Orbitron', sans-serif", fontWeight: 900 }}>{score.toLocaleString()}</div>
        </div>
        <div style={{ textAlign: 'center' }}>
          <div style={{ color: '#00aa00', fontSize: '0.75rem', letterSpacing: '3px', marginBottom: '4px' }}>NIVEAU</div>
          <div style={{ color: '#00ff88', fontSize: '1.8rem', fontFamily: "'Orbitron', sans-serif", fontWeight: 900 }}>{niveau}</div>
        </div>
        <div style={{ textAlign: 'center' }}>
          <div style={{ color: '#ff4444', fontSize: '0.75rem', letterSpacing: '3px', marginBottom: '4px' }}>VIES</div>
          <div style={{ fontSize: '1.5rem' }}>{'❤️'.repeat(vies)}{'🖤'.repeat(Math.max(0, 3 - vies))}</div>
        </div>
        <div style={{ textAlign: 'right' }}>
          <div style={{ color: '#8833ff', fontSize: '0.75rem', letterSpacing: '3px', marginBottom: '4px' }}>RECORD</div>
          <div style={{ color: '#cc88ff', fontSize: '1.4rem', fontFamily: "'Orbitron', sans-serif", fontWeight: 700 }}>{highscore.toLocaleString()}</div>
        </div>
      </div>

      {/* ZONE DE JEU */}
      <div ref={zoneRef} style={{ position: 'relative', width: '100%', height: '380px', background: 'radial-gradient(ellipse at center, #060c1a 0%, #020408 100%)', border: '1px solid rgba(255,215,0,0.15)', borderTop: 'none', overflow: 'hidden', cursor: 'crosshair' }}>

        {/* Grille déco */}
        <svg style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', opacity: 0.04 }}>
          <defs><pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse"><path d="M 40 0 L 0 0 0 40" fill="none" stroke="#00ff88" strokeWidth="0.5"/></pattern></defs>
          <rect width="100%" height="100%" fill="url(#grid)"/>
        </svg>

        {!actif && !gameOver && (
          <div style={{ position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '20px' }}>
            <div style={{ fontSize: '4rem', filter: 'drop-shadow(0 0 20px #ffd700)' }}>⚔️</div>
            <h3 style={{ color: '#ffd700', fontFamily: "'Orbitron', sans-serif", fontSize: '1.4rem', letterSpacing: '3px', margin: 0 }}>CYBER DEFENSE</h3>
            <p style={{ color: '#5a6a7a', fontSize: '0.95rem', textAlign: 'center', maxWidth: '300px', lineHeight: 1.7, margin: 0 }}>
              Clique sur les virus, hackers et malwares avant qu'ils atteignent le bas ! Fais des combos pour multiplier les points !
            </p>
            <div style={{ display: 'flex', gap: '16px', fontSize: '1.5rem' }}>
              {ENNEMIS_TYPES.map(e => <span key={e.nom} title={`${e.nom} — ${e.points}pts`}>{e.emoji}</span>)}
            </div>
            <button onClick={demarrer} style={{ background: 'linear-gradient(135deg, #00aa00, #007700)', color: '#fff', border: 'none', borderRadius: '50px', padding: '14px 40px', fontSize: '1rem', fontWeight: 700, fontFamily: "'Rajdhani', sans-serif", letterSpacing: '3px', textTransform: 'uppercase', cursor: 'pointer', boxShadow: '0 0 20px rgba(0,170,0,0.4)' }}>
              🎮 JOUER
            </button>
          </div>
        )}

        {gameOver && (
          <div style={{ position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '16px', background: 'rgba(0,0,0,0.85)' }}>
            <div style={{ fontSize: '3.5rem' }}>💥</div>
            <h3 style={{ color: '#ff4444', fontFamily: "'Orbitron', sans-serif", fontSize: '1.4rem', margin: 0 }}>GAME OVER</h3>
            <div style={{ color: '#ffd700', fontSize: '1.1rem', fontFamily: "'Orbitron', sans-serif" }}>Score : {score.toLocaleString()}</div>
            {score >= highscore && score > 0 && <div style={{ color: '#00ff88', fontSize: '0.9rem', letterSpacing: '2px' }}>🏆 NOUVEAU RECORD !</div>}
            <button onClick={demarrer} style={{ background: 'linear-gradient(135deg, #ff4400, #aa2200)', color: '#fff', border: 'none', borderRadius: '50px', padding: '12px 36px', fontSize: '1rem', fontWeight: 700, fontFamily: "'Rajdhani', sans-serif", letterSpacing: '2px', cursor: 'pointer', marginTop: '8px' }}>
              🔄 REJOUER
            </button>
          </div>
        )}

        {/* ENNEMIS */}
        {ennemis.map(e => (
          <div key={e.id} className="ennemi-sprite" onClick={() => tuerEnnemi(e.id, e.x, e.y, e.points)}
            style={{ position: 'absolute', left: e.x, top: e.y, width: e.taille, height: e.taille, fontSize: `${e.taille * 0.6}px`, display: 'flex', flexDirection: 'column', alignItems: 'center', filter: `drop-shadow(0 0 8px ${e.couleur})` }}>
            <span>{e.emoji}</span>
            <span style={{ fontSize: '8px', color: e.couleur, fontWeight: 700, letterSpacing: '1px' }}>{e.nom}</span>
          </div>
        ))}

        {/* EXPLOSIONS */}
        {explosions.map(ex => (
          <div key={ex.id} style={{ position: 'absolute', left: ex.x, top: ex.y, pointerEvents: 'none' }}>
            <div style={{ animation: 'explode 0.5s ease forwards', fontSize: '2rem' }}>💥</div>
            <div style={{ animation: 'floatUp 0.6s ease forwards', color: '#ffd700', fontFamily: "'Orbitron', sans-serif", fontSize: '14px', fontWeight: 900, whiteSpace: 'nowrap' }}>
              +{ex.gain}{ex.combo >= 3 ? ` x${ex.combo}!` : ''}
            </div>
          </div>
        ))}

        {/* COMBO DISPLAY */}
        {comboDisplay && (
          <div style={{ position: 'absolute', left: '50%', top: '40%', transform: 'translateX(-50%)', animation: 'comboFlash 0.8s ease forwards', pointerEvents: 'none', zIndex: 10 }}>
            <div style={{ color: '#ff6600', fontFamily: "'Orbitron', sans-serif", fontSize: '2.5rem', fontWeight: 900, textShadow: '0 0 20px #ff6600', whiteSpace: 'nowrap' }}>
              COMBO x{comboDisplay.val}! 🔥
            </div>
          </div>
        )}

        {/* Combo actuel */}
        {actif && combo >= 2 && (
          <div style={{ position: 'absolute', top: '12px', left: '12px', background: 'rgba(255,100,0,0.2)', border: '1px solid #ff6600', borderRadius: '8px', padding: '6px 12px' }}>
            <span style={{ color: '#ff6600', fontSize: '0.85rem', fontFamily: "'Orbitron', sans-serif", fontWeight: 700 }}>🔥 COMBO x{combo}</span>
          </div>
        )}
      </div>

      {/* FOOTER */}
      <div style={{ background: 'rgba(10,15,30,0.9)', border: '1px solid rgba(255,215,0,0.2)', borderTop: 'none', borderRadius: '0 0 16px 16px', padding: '12px 24px', display: 'flex', justifyContent: 'center', gap: '24px' }}>
        {ENNEMIS_TYPES.map(e => (
          <div key={e.nom} style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '1.2rem' }}>{e.emoji}</div>
            <div style={{ color: e.couleur, fontSize: '0.7rem', fontWeight: 700 }}>{e.points}pts</div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default MiniJeu;
